import React, { useState, useEffect, useRef } from 'react';

const InputArea = ({ currentStep, onSendMessage, isTyping }) => {
  const [inputValue, setInputValue] = useState('');
  const inputRef = useRef(null);

  // Auto-focus the input whenever the step changes
  useEffect(() => {
    if (!isTyping && inputRef.current) {
      inputRef.current.focus();
    }
  }, [currentStep, isTyping]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputValue.trim() && !isTyping) {
      onSendMessage(inputValue);
      setInputValue('');
    }
  };

  if (!currentStep || isTyping) return null;

  return (
    <div className="w-full max-w-2xl mx-auto mt-8 px-4">
      {currentStep.type === 'text' || currentStep.type === 'voice_text' ? (
        <form onSubmit={handleSubmit} className="flex flex-col items-center">
          <input
            ref={inputRef}
            type="text"
            className="w-full text-center text-3xl font-light py-6 bg-transparent border-b-2 border-slate-200 focus:border-emerald-400 outline-none transition-all duration-500 text-slate-700 placeholder:text-slate-200"
            placeholder="Type your answer here..."
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
          />
          
          <div className="mt-8 flex items-center gap-6">
            {currentStep.type === 'voice_text' && (
              <button 
                type="button" 
                className="group flex items-center gap-3 px-6 py-3 bg-emerald-50 text-emerald-600 rounded-full hover:bg-emerald-600 hover:text-white transition-all duration-300"
              >
                <span className="text-xl">🎤</span>
                <span className="font-medium text-sm">Speak Instead</span>
              </button>
            )}
            
            <button 
              type="submit"
              className={`px-10 py-3 rounded-full font-semibold transition-all duration-300 ${
                inputValue.trim() 
                ? 'bg-slate-800 text-white shadow-lg translate-y-[-2px]' 
                : 'bg-slate-100 text-slate-400 cursor-not-allowed'
              }`}
            >
              Continue
            </button>
          </div>
          
          <p className="mt-4 text-[10px] text-slate-400 uppercase tracking-widest font-bold">
            Press Enter to continue
          </p>
        </form>
      ) : currentStep.type === 'choice' ? (
        <div className="grid grid-cols-1 gap-4 w-full max-w-sm mx-auto">
          {currentStep.options.map((option) => (
            <button
              key={option}
              onClick={() => onSendMessage(option)}
              className="group flex justify-between items-center py-5 px-8 bg-white border-2 border-slate-100 rounded-2xl hover:border-emerald-500 hover:bg-emerald-50 transition-all duration-300 transform hover:scale-[1.02]"
            >
              <span className="text-lg font-medium text-slate-700 group-hover:text-emerald-700">{option}</span>
              <span className="text-slate-300 group-hover:text-emerald-500">→</span>
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
};

export default InputArea;
